import{_ as t,o,c as a,a5 as r}from"./chunks/framework.CxGAAJIM.js";const u=JSON.parse('{"title":"Metadata catalog","description":"","frontmatter":{},"headers":[],"relativePath":"reference/resources/metadata-catalog.md","filePath":"reference/resources/metadata-catalog.md"}'),n={name:"reference/resources/metadata-catalog.md"};function s(i,e,d,c,l,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="metadata-catalog" tabindex="-1">Metadata catalog <a class="header-anchor" href="#metadata-catalog" aria-label="Permalink to &quot;Metadata catalog&quot;">​</a></h1><p>Platform Mesh uses a small set of API groups, labels, finalizers, and annotations to identify the objects it manages and to wire them into the rest of the stack. This page is the canonical reference for that metadata so that when you see a label like <code>core.platform-mesh.io/org</code> or a finalizer like <code>account.core.platform-mesh.io/finalizer</code> in a YAML file, you know what owns it and what to expect.</p><div class="tip custom-block"><p class="custom-block-title">Where Platform Mesh metadata appears</p><p>&quot;Platform Mesh metadata&quot; is a loose phrase. Several mechanisms are in use:</p><ul><li><strong>API groups</strong> identify the CRDs Platform Mesh defines.</li><li><strong>Labels</strong> wire Platform Mesh resources into the portal, the marketplace, and identity scoping.</li><li><strong>Finalizers</strong> ensure the right cleanup order when objects are deleted.</li><li>True <strong>annotations</strong> are used sparingly; most Platform Mesh-specific information lives in dedicated CRD fields rather than annotations on existing kcp or Kubernetes objects.</li></ul></div><h2 id="api-groups" tabindex="-1">API groups <a class="header-anchor" href="#api-groups" aria-label="Permalink to &quot;API groups&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Group</th><th>Owner</th><th>Resources</th></tr></thead><tbody><tr><td><code>core.platform-mesh.io/v1alpha1</code></td><td>account-operator, IAM service</td><td><code>Account</code>, <code>AccountExtension</code>, <code>Store</code></td></tr><tr><td><code>ui.platform-mesh.io/v1alpha1</code></td><td>extension manager operator</td><td><code>ContentConfiguration</code>, <code>ExtensionClass</code> (portal extensions)</td></tr></tbody></table><p>API resources outside these groups are upstream kcp (<code>apis.kcp.io</code>, <code>tenancy.kcp.io</code>), upstream Kubernetes, or provider-specific.</p><h2 id="labels" tabindex="-1">Labels <a class="header-anchor" href="#labels" aria-label="Permalink to &quot;Labels&quot;">​</a></h2><p>Platform Mesh attaches labels to its own resources and, in some cases, to upstream resources it manages.</p><table tabindex="0"><thead><tr><th>Label</th><th>Used on</th><th>Purpose</th></tr></thead><tbody><tr><td><code>core.platform-mesh.io/org</code></td><td>WorkspaceTypes managed by the account-operator</td><td>Scopes a workspace type to a specific organization so child accounts inherit the right RBAC.</td></tr><tr><td><code>ui.platform-mesh.io/entity</code></td><td>ContentConfiguration</td><td>Attaches the configuration to a portal navigation entity (for example, <code>core_platform-mesh_io_account</code> to extend Account pages).</td></tr><tr><td><code>extensions.openmfp.io</code></td><td>ContentConfiguration (legacy)</td><td>Maps to an <code>ExtensionClass</code> in older deployments. New deployments prefer <code>ui.platform-mesh.io/entity</code>.</td></tr></tbody></table><p>Provider authors generally do <strong>not</strong> need to set Platform Mesh labels on APIExports or APIBindings — onboarding scripts and operators handle that.</p><h2 id="finalizers" tabindex="-1">Finalizers <a class="header-anchor" href="#finalizers" aria-label="Permalink to &quot;Finalizers&quot;">​</a></h2><p>Finalizers ensure that Platform Mesh resources are torn down in the right order — for example, an Account&#39;s IAM Store must be cleaned up before the workspace itself is deleted, otherwise stranded permissions remain in OpenFGA.</p><table tabindex="0"><thead><tr><th>Finalizer</th><th>Set by</th><th>Purpose</th></tr></thead><tbody><tr><td><code>account.core.platform-mesh.io/finalizer</code></td><td>account-operator</td><td>Holds the Account until its workspace is deleted.</td></tr><tr><td><code>account.core.platform-mesh.io/info</code></td><td>account-operator</td><td>Holds the Account until its account-info status fields are reconciled to children.</td></tr><tr><td><code>workspacetype.core.platform-mesh.io/finalizer</code></td><td>account-operator (workspacetype subroutine)</td><td>Holds the WorkspaceType created for an org until all child workspaces are gone.</td></tr><tr><td><code>platform-mesh.core.platform-mesh.io/finalizer</code></td><td>platform-mesh-operator</td><td>Coordinates teardown of platform-level provider secrets and kcp setup state.</td></tr></tbody></table><p>You should not normally remove these finalizers by hand. If a resource is stuck on a finalizer, check the operator logs to see which subroutine is blocked rather than force-deleting.</p><h2 id="annotations" tabindex="-1">Annotations <a class="header-anchor" href="#annotations" aria-label="Permalink to &quot;Annotations&quot;">​</a></h2><p>Pure annotations on Platform Mesh-managed objects are sparse. The codebase uses Kubebuilder-generated annotations (<code>controller-gen.kubebuilder.io/version</code>) on CRDs and standard Kubernetes annotations (for example, <code>service.binding/*</code> from the <a href="https://servicebinding.io/" target="_blank" rel="noreferrer">Service Binding spec</a> on operator-managed objects), but Platform Mesh does not impose a custom annotation scheme on top of them today.</p><p>Annotations specifically owned by Platform Mesh use the <code>core.platform-mesh.io/*</code> prefix. If you encounter a Platform Mesh annotation in a real cluster that is not documented here, it is likely operator-internal state that is safe to ignore from a user perspective.</p><h2 id="documentation-status" tabindex="-1">Documentation status <a class="header-anchor" href="#documentation-status" aria-label="Permalink to &quot;Documentation status&quot;">​</a></h2><p>This catalog is updated as Platform Mesh component owners contribute the supported keys, values, and ownership rules. Each future entry should include:</p><ul><li>full key</li><li>value format</li><li>writing component</li><li>reading component</li><li>whether users may set it</li><li>lifecycle and compatibility guarantees</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./account-resource.html">Account resource</a> — uses the <code>core.platform-mesh.io</code> API group and its finalizers</li><li><a href="./content-configuration.html">ContentConfiguration</a> — uses the <code>ui.platform-mesh.io</code> API group and the <code>ui.platform-mesh.io/entity</code> label</li><li><a href="/pr-preview/pr-162/concepts/account-model.html">Account model</a></li><li><a href="/pr-preview/pr-162/reference/components/">Component reference</a></li></ul>',22)])])}const m=t(n,[["render",s]]);export{u as __pageData,m as default};
